/* ─── HELPERS ───────────────────────────────────────────────────── */
const ARS = n => new Intl.NumberFormat("es-AR",{style:"currency",currency:"ARS",maximumFractionDigits:0}).format(n);

function calcular(lista, desc, iva, markup) {
  const neto   = lista  * (1 - desc   / 100);
  const conIva = neto   * (1 + iva    / 100);
  const venta  = conIva * (1 + markup / 100);
  return { neto, conIva, venta };
}

